/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Implements NotificationAdapter so it can be registered with
 * NotificationService for the 'webhook' channel.
 *
 * Features:
 * - Sends JSON payload via HTTP POST to a configured URL
 * - Pluggable HTTP transport for testing (defaults to fetch)
 * - In-memory transport for testing; swap for real HTTP in production
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookPayload {
  type: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  sentAt: string;
}

export interface WebhookTransport {
  post(url: string, payload: WebhookPayload): Promise<{ success: boolean; error?: string }>;
}

export interface WebhookAdapterConfig {
  url: string;
  transport?: WebhookTransport;
}

/**
 * In-memory transport that stores webhook deliveries for inspection.
 * Used when no external transport is provided.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private deliveries: Array<{ url: string; payload: WebhookPayload }> = [];

  async post(url: string, payload: WebhookPayload): Promise<{ success: boolean; error?: string }> {
    this.deliveries.push({ url, payload });
    return { success: true };
  }

  getDeliveries(): Array<{ url: string; payload: WebhookPayload }> {
    return [...this.deliveries];
  }

  clear(): void {
    this.deliveries = [];
  }
}

function formatPayload(notificationPayload: NotificationPayload): WebhookPayload {
  return {
    type: notificationPayload.type,
    recipient: notificationPayload.recipient,
    subject: notificationPayload.subject,
    body: notificationPayload.body,
    metadata: notificationPayload.metadata,
    sentAt: new Date().toISOString(),
  };
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private config: WebhookAdapterConfig;
  private transport: WebhookTransport;
  private sentWebhooks: Array<{ url: string; payload: WebhookPayload; sentAt: Date }> = [];

  constructor(config: WebhookAdapterConfig) {
    this.config = config;
    this.transport = this.config.transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a notification as a webhook POST.
   *
   * Steps:
   * 1. Validate the configured URL
   * 2. Format the notification payload as JSON
   * 3. POST it via the configured transport
   *
   * Must not throw — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate URL
      const url = this.config.url.trim();
      if (!url) {
        this.logger.warn('Webhook URL is empty');
        return { success: false, channel: 'webhook', error: 'Webhook URL is empty' };
      }

      // 2. Format payload
      const webhookPayload = formatPayload(payload);

      // 3. POST via transport
      this.logger.info(`Sending webhook to ${url}: ${payload.subject}`);

      const result = await this.transport.post(url, webhookPayload);

      if (result.success) {
        this.sentWebhooks.push({
          url,
          payload: webhookPayload,
          sentAt: new Date(),
        });
      }

      if (!result.success) {
        this.logger.error(`Failed to send webhook to ${url}: ${result.error}`);
        return { success: false, channel: 'webhook', error: result.error };
      }

      return { success: true, channel: 'webhook' };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error';
      this.logger.error(`Unexpected error sending webhook: ${errorMessage}`);
      return { success: false, channel: 'webhook', error: errorMessage };
    }
  }

  /**
   * Get all webhooks sent by this adapter (useful for testing).
   */
  getSentWebhooks(): Array<{ url: string; payload: WebhookPayload; sentAt: Date }> {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhook history (useful for testing).
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type {
  WebhookTransport,
  WebhookPayload,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;
  const webhookUrl = 'https://hooks.example.com/notifications';

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({ url: webhookUrl, transport });
  });

  describe('send', () => {
    it('should send an order confirmation webhook with formatted payload', async () => {
      const payload: NotificationPayload = {
        type: 'order:confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        metadata: { orderId: 'order-1', userId: 'user-1' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');

      const deliveries = transport.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.url).toBe(webhookUrl);
      expect(deliveries[0]?.payload.type).toBe('order:confirmation');
      expect(deliveries[0]?.payload.recipient).toBe('alice@example.com');
      expect(deliveries[0]?.payload.subject).toBe('Order Confirmation: order-1');
      expect(deliveries[0]?.payload.body).toContain('Widget x2');
      expect(deliveries[0]?.payload.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
      expect(deliveries[0]?.payload.sentAt).toBeDefined();
    });

    it('should send an order status update webhook', async () => {
      const payload: NotificationPayload = {
        type: 'order:status-update',
        recipient: 'alice@example.com',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to confirmed.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'confirmed' },
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.payload.type).toBe('order:status-update');
      expect(deliveries[0]?.payload.metadata?.newStatus).toBe('confirmed');
    });

    it('should send a welcome webhook', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'bob@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.payload.type).toBe('user:welcome');
      expect(deliveries[0]?.payload.body).toBe('Welcome to TaskFlow Pro.');
    });

    it('should send a profile updated webhook', async () => {
      const payload: NotificationPayload = {
        type: 'user:profile-updated',
        recipient: 'carol@example.com',
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.payload.type).toBe('user:profile-updated');
    });

    it('should track sent webhooks via getSentWebhooks()', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      await adapter.send(payload);

      const sent = adapter.getSentWebhooks();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.url).toBe(webhookUrl);
      expect(sent[0]?.payload.subject).toBe('Welcome!');
    });
  });

  describe('URL validation', () => {
    it('should reject empty URL', async () => {
      const emptyUrlAdapter = new WebhookAdapter({ url: '', transport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await emptyUrlAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
      expect(transport.getDeliveries()).toHaveLength(0);
    });

    it('should reject whitespace-only URL', async () => {
      const wsAdapter = new WebhookAdapter({ url: '   ', transport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await wsAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });
  });

  describe('transport error handling', () => {
    it('should return failed result when transport fails', async () => {
      const failingTransport: WebhookTransport = {
        async post(): Promise<{ success: boolean; error?: string }> {
          return { success: false, error: 'HTTP 500 Internal Server Error' };
        },
      };

      const failAdapter = new WebhookAdapter({ url: webhookUrl, transport: failingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('HTTP 500 Internal Server Error');
      expect(failAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should catch transport exceptions and return failed result', async () => {
      const throwingTransport: WebhookTransport = {
        async post(): Promise<{ success: boolean; error?: string }> {
          throw new Error('Network timeout');
        },
      };

      const throwAdapter = new WebhookAdapter({ url: webhookUrl, transport: throwingTransport });
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
      };

      const result = await throwAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
    });
  });

  describe('configuration', () => {
    it('should use InMemoryWebhookTransport by default', () => {
      const defaultAdapter = new WebhookAdapter({ url: webhookUrl });
      expect(defaultAdapter.getTransport()).toBeInstanceOf(InMemoryWebhookTransport);
    });
  });

  describe('clearSentWebhooks', () => {
    it('should clear sent webhook history', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome.',
      };

      await adapter.send(payload);
      expect(adapter.getSentWebhooks()).toHaveLength(1);

      adapter.clearSentWebhooks();
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  describe('InMemoryWebhookTransport', () => {
    it('should store and return deliveries', async () => {
      const webhookPayload: WebhookPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        sentAt: new Date().toISOString(),
      };

      const result = await transport.post(webhookUrl, webhookPayload);

      expect(result.success).toBe(true);
      expect(transport.getDeliveries()).toHaveLength(1);
      expect(transport.getDeliveries()[0]?.url).toBe(webhookUrl);
    });

    it('should clear deliveries', async () => {
      const webhookPayload: WebhookPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        sentAt: new Date().toISOString(),
      };

      await transport.post(webhookUrl, webhookPayload);
      transport.clear();
      expect(transport.getDeliveries()).toHaveLength(0);
    });
  });

  describe('payload format', () => {
    it('should include sentAt as ISO string in payload', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome.',
      };

      await adapter.send(payload);

      const deliveries = transport.getDeliveries();
      const sentAt = deliveries[0]?.payload.sentAt;
      expect(sentAt).toBeDefined();
      expect(new Date(sentAt!).toISOString()).toBe(sentAt);
    });

    it('should handle payload without metadata', async () => {
      const payload: NotificationPayload = {
        type: 'user:welcome',
        recipient: 'alice@example.com',
        subject: 'Welcome!',
        body: 'Welcome.',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      const deliveries = transport.getDeliveries();
      expect(deliveries[0]?.payload.metadata).toBeUndefined();
    });
  });
});

